import se.skl.rivta.testsupport.soapui.datasource.XmlDataReader
import com.eviware.soapui.support.GroovyUtils

def utils = new GroovyUtils(context)
def dataFile = new File(utils.projectPath + "/data.xml")
def source = new XmlDataReader(context, dataFile)

source.load(testRunner.testCase.getName())

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import groovy.xml.StreamingMarkupBuilder
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange)

//Hämta alla poster
context.allRecords = ca.getContentRecords()

//Spara hasMore
def xml = new XmlSlurper().parseText(messageExchange.responseContentAsXml)
def hasMore = xml.Body.GetCareDocumentationResponse.hasMore.toString()
messageExchange.modelItem.testStep.testCase.setPropertyValue( "hasMore" , hasMore != "" ? "true" : "false" )

con:config.script:
def documentTime = '/urn:careDocumentation/urn1:header/urn1:record/urn1:timestamp'
def authorTime = '/urn:careDocumentation/urn1:header/urn1:author/urn1:timestamp'
def signatureTime = '/urn:careDocumentation/urn1:header/urn1:signature/urn1:timestamp'
def dissentingAuthorTime = '/urn:careDocumentation/urn1:body/urn1:dissentingOpinion/urn1:authorTime'

if (!context.allRecords) {
	testRunner.fail("No records")
	return
}
if (!context.dates) {
	def documentTimes = context.allRecords.collect { record -> record.firstElementAt(documentTime) }
	def authorTimes = context.allRecords.collect { record -> record.firstElementAt(authorTime) }
	def signatureTimes = context.allRecords.collect { record -> record.firstElementAt(signatureTime) }
	def dissentingAuthorTimes = context.allRecords.collect { record -> record.allElementsAt(dissentingAuthorTime) }.flatten()
	context.dates = documentTimes.findAll().collect{ it[0..7] }.unique()
	context.dates += authorTimes.findAll().collect{ it[0..7] }.unique()
	context.dates += signatureTimes.findAll().collect{ it[0..7] }.unique()
	context.dates += dissentingAuthorTimes.findAll().collect{ it[0..7] }.unique()
	//log.info(context.dates)
	context.dates = context.dates.findAll().collect{ it[0..7] }.unique()

	if (!context.dates) {
		testRunner.fail("No data")
	}
}

context.datePeriodStart = context.dates.pop()
context.datePeriodEnd = context.datePeriodStart

[context.datePeriodStart, context.datePeriodEnd]

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import groovy.xml.StreamingMarkupBuilder
import se.skl.rivta.tksupport.soapui.ContentAssertions

//Initiering
def requestStartFilled = context.datePeriodStart + '000000'
def requestEndFilled = context.datePeriodEnd + '235959'

def ca = new ContentAssertions(context, messageExchange)
def filteredRecords = ca.getContentRecords()
def noOfFilteredRecords = filteredRecords.size

def documentTime = '/urn:careDocumentation/urn1:header/urn1:record/urn1:timestamp'
def authorTime = '/urn:careDocumentation/urn1:header/urn1:author/urn1:timestamp'
def signatureTime = '/urn:careDocumentation/urn1:header/urn1:signature/urn1:timestamp'
def dissentingAuthorTime = '/urn:careDocumentation/urn1:body/urn1:dissentingOpinion/urn1:authorTime'
def id = '/urn:careDocumentation/urn1:header/urn1:record/urn1:id/urn1:root'

//creates lists containing all records which are within the timeintervall
def documentTimestampInTimeRange = filteredRecords.findAll { record -> 
	record.firstElementAt(documentTime) != null && 
	record.timestampInRange(documentTime, requestStartFilled, requestEndFilled)
}
def authorTimestampInTimeRange = filteredRecords.findAll { record -> 
	record.firstElementAt(authorTime) != null && 
	record.timestampInRange(authorTime, requestStartFilled, requestEndFilled)
}
def signatureTimestampInTimeRange = filteredRecords.findAll { record -> 
	record.firstElementAt(signatureTime) != null && 
	record.timestampInRange(signatureTime, requestStartFilled, requestEndFilled)
}
def dissentingAuthorTimestampInTimeRange = filteredRecords.findAll { record -> 
	record.allElementsAt(dissentingAuthorTime).any {it >= requestStartFilled && it <= requestEndFilled}
}

//List of unique records which are within the timeintervall
def records = (documentTimestampInTimeRange + authorTimestampInTimeRange + signatureTimestampInTimeRange + dissentingAuthorTimestampInTimeRange).unique()

//Kontrollera att alla poster har datum inom sökintervallet
assert(records.size == noOfFilteredRecords)

con:config.script:
if (context.dates.any()) {
	testRunner.gotoStepByName( "Calculate interval")
}
else if (testRunner.getResults().any{it.getStatus().toString() == 'FAILED'}) {
	testRunner.fail("One or more steps failed")
}

