def signatureId = 'urn:careDocumentation/urn1:header/urn1:signature/urn1:id/urn1:extension'
def timestamp = 'urn:careDocumentation/urn1:header/urn1:signature/urn1:timestamp'
def locktime = 'urn:careDocumentation/urn1:header/urn1:accessControlHeader/urn1:lockTime'

def condition = { record ->
	def hasSignatureId = record.firstElementAt(signatureId)
	def hasTimestamp = record.firstElementAt(timestamp)
	def hasLocktime = record.firstElementAt(locktime)	
	log.info( "hasSignatureId: " + hasSignatureId)
	log.info( "hasTimestamp: " + hasTimestamp)
	log.info( "hasLocktime: " + hasLocktime)
	return !hasSignatureId && !hasTimestamp && !hasLocktime
}

def recordInfo = sprintf("Svaret innehåller ingen osignerad post, dvs där signatur, signeringstidpunkt och låstid saknas.")

ca.assertForAnyRecord(condition, recordInfo)

