//Nollställ räknare
context.hasMoreCounter = 0
context.hasMoreLimit = 10

source.load(testRunner.testCase.getName())

con:configuration.scriptText:
import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertNonEmptyResponse()

def groovyUtils = new com.eviware.soapui.support.GroovyUtils( context )

// Hämta responsen
def holder = groovyUtils.getXmlHolder( "Call GetCareDocumentation 1#Response" )
def xml = new XmlSlurper().parseText(holder.getXml())

// Spara parametrar till nästa anrop och hantera eventuella encodings i parametrarna
def hasMorelogicalAdress = xml.Body.GetCareDocumentationResponse.hasMore.logicalAddress.toString()
def hasMoreReference = xml.Body.GetCareDocumentationResponse.hasMore.reference.toString()

def escapedLogicalAdress = hasMorelogicalAdress.replaceAll("&", "&amp;")
									.replaceAll("<", "&lt;")
         								.replaceAll(">", "&gt;")
         								.replaceAll("\"", "&quot;")
         								.replaceAll("\'", "&apos;")
def escapedReference = hasMoreReference.replaceAll("&", "&amp;")
									.replaceAll("<", "&lt;")
         								.replaceAll(">", "&gt;")
         								.replaceAll("\"", "&quot;")
         								.replaceAll("\'", "&apos;")

context.hasMorelogicalAdress = escapedLogicalAdress
context.hasMoreReference = escapedReference

log.info(escapedLogicalAdress)
log.info(escapedReference)

assert xml.Body.GetCareDocumentationResponse.hasMore.size() != 0 : "hasMore saknas"

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertSchematronConstraints()

import se.skl.rivta.tksupport.soapui.ContentAssertions
def ca = new ContentAssertions(context, messageExchange, log)
ca.assertNonEmptyResponse()

con:config.script:
def groovyUtils = new com.eviware.soapui.support.GroovyUtils( context )

// Hämta responsen
def holder = groovyUtils.getXmlHolder( "Call GetCareDocumentation 2#Response" )
def xml = new XmlSlurper().parseText(holder.getXml())

//Om det finns HasMore så fortsätter vi att anropa
if (xml.Body.GetCareDocumentationResponse.hasMore.size() > 0){
	if (context.hasMoreCounter < context.hasMoreLimit){
		context.hasMoreCounter = context.hasMoreCounter + 1
		// Spara parametrar till nästa anrop och hantera eventuella encodings i parametrarna
		def hasMorelogicalAdress = xml.Body.GetCareDocumentationResponse.hasMore.logicalAddress.toString()
		def hasMoreReference = xml.Body.GetCareDocumentationResponse.hasMore.reference.toString()

		def escapedLogicalAdress = hasMorelogicalAdress.replaceAll("&", "&amp;")
										.replaceAll("<", "&lt;")
	         								.replaceAll(">", "&gt;")
	         								.replaceAll("\"", "&quot;")
	         								.replaceAll("\'", "&apos;")
		def escapedReference = hasMoreReference.replaceAll("&", "&amp;")
										.replaceAll("<", "&lt;")
	         								.replaceAll(">", "&gt;")
	         								.replaceAll("\"", "&quot;")
	         								.replaceAll("\'", "&apos;")	
		context.hasMorelogicalAdress = escapedLogicalAdress
		context.hasMoreReference = escapedReference
		//Hoppa till Sleep om det finns mer data att hämta
		testRunner.gotoStepByName( "Sleep")
	}
	else
	{
		//
		testRunner.fail("No of calls exceeded the parameter hasMoreLimit defined in section ReadData")
	}
}
log.info("Finnished")

